int maximum(int a, int b, int c) {
    int k;
    if (b >= a)
        k = b;
    else
        k = a;
    if (c >= k)
        return c;
    else
        return k;
}

static const int BLOCK_SZ = 16;

void needle_shared_1(int* referrence, int* matrix_cuda, int cols, int penalty, int i, int block_width) {
    int num_blocks = i;
#pragma omp parallel for schedule(static)
    for (int bx = 0; bx < num_blocks; bx++) {
        int b_index_x = bx;
        int b_index_y = i - 1 - bx;

        int index = cols * BLOCK_SZ * b_index_y + BLOCK_SZ * b_index_x + (cols + 1);
        int index_n = cols * BLOCK_SZ * b_index_y + BLOCK_SZ * b_index_x + (1);
        int index_w = cols * BLOCK_SZ * b_index_y + BLOCK_SZ * b_index_x + (cols);
        int index_nw = cols * BLOCK_SZ * b_index_y + BLOCK_SZ * b_index_x;

        int temp[BLOCK_SZ + 1][BLOCK_SZ + 1];
        int ref[BLOCK_SZ][BLOCK_SZ];

        temp[0][0] = matrix_cuda[index_nw];
        for (int ty = 0; ty < BLOCK_SZ; ty++) {
            for (int tx_inner = 0; tx_inner < BLOCK_SZ; tx_inner++) {
                ref[ty][tx_inner] = referrence[index + cols * ty + tx_inner];
            }
        }
        for (int tx_inner = 0; tx_inner < BLOCK_SZ; tx_inner++) {
            temp[tx_inner + 1][0] = matrix_cuda[index_w + cols * tx_inner];
        }
        for (int tx_inner = 0; tx_inner < BLOCK_SZ; tx_inner++) {
            temp[0][tx_inner + 1] = matrix_cuda[index_n + tx_inner];
        }

        for (int m = 0; m < BLOCK_SZ; m++) {
            for (int tx_inner = 0; tx_inner < BLOCK_SZ; tx_inner++) {
                if (m >= tx_inner) {
                    int t_index_x = tx_inner + 1;
                    int t_index_y = m - tx_inner + 1;
                    temp[t_index_y][t_index_x] = maximum(
                        temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
                        temp[t_index_y][t_index_x - 1] - penalty,
                        temp[t_index_y - 1][t_index_x] - penalty);
                }
            }
        }

        for (int m = BLOCK_SZ - 2; m >= 0; m--) {
            for (int tx_inner = 0; tx_inner < BLOCK_SZ; tx_inner++) {
                if (m >= tx_inner) {
                    int t_index_x = tx_inner + BLOCK_SZ - m;
                    int t_index_y = BLOCK_SZ - tx_inner;
                    temp[t_index_y][t_index_x] = maximum(
                        temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
                        temp[t_index_y][t_index_x - 1] - penalty,
                        temp[t_index_y - 1][t_index_x] - penalty);
                }
            }
        }

        for (int ty = 0; ty < BLOCK_SZ; ty++) {
            for (int tx_inner = 0; tx_inner < BLOCK_SZ; tx_inner++) {
                matrix_cuda[index + ty * cols + tx_inner] = temp[ty + 1][tx_inner + 1];
            }
        }
    }
}

void needle_shared_2(int* referrence, int* matrix_cuda, int cols, int penalty, int i, int block_width) {
    int num_blocks = i;
#pragma omp parallel for schedule(static)
    for (int bx = 0; bx < num_blocks; bx++) {
        int b_index_x = bx + block_width - i;
        int b_index_y = block_width - bx - 1;

        int index = cols * BLOCK_SZ * b_index_y + BLOCK_SZ * b_index_x + (cols + 1);
        int index_n = cols * BLOCK_SZ * b_index_y + BLOCK_SZ * b_index_x + (1);
        int index_w = cols * BLOCK_SZ * b_index_y + BLOCK_SZ * b_index_x + (cols);
        int index_nw = cols * BLOCK_SZ * b_index_y + BLOCK_SZ * b_index_x;

        int temp[BLOCK_SZ + 1][BLOCK_SZ + 1];
        int ref[BLOCK_SZ][BLOCK_SZ];

        for (int ty = 0; ty < BLOCK_SZ; ty++) {
            for (int tx_inner = 0; tx_inner < BLOCK_SZ; tx_inner++) {
                ref[ty][tx_inner] = referrence[index + cols * ty + tx_inner];
            }
        }

        temp[0][0] = matrix_cuda[index_nw];
        for (int tx_inner = 0; tx_inner < BLOCK_SZ; tx_inner++) {
            temp[tx_inner + 1][0] = matrix_cuda[index_w + cols * tx_inner];
        }
        for (int tx_inner = 0; tx_inner < BLOCK_SZ; tx_inner++) {
            temp[0][tx_inner + 1] = matrix_cuda[index_n + tx_inner];
        }

        for (int m = 0; m < BLOCK_SZ; m++) {
            for (int tx_inner = 0; tx_inner < BLOCK_SZ; tx_inner++) {
                if (m >= tx_inner) {
                    int t_index_x = tx_inner + 1;
                    int t_index_y = m - tx_inner + 1;
                    temp[t_index_y][t_index_x] = maximum(
                        temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
                        temp[t_index_y][t_index_x - 1] - penalty,
                        temp[t_index_y - 1][t_index_x] - penalty);
                }
            }
        }

        for (int m = BLOCK_SZ - 2; m >= 0; m--) {
            for (int tx_inner = 0; tx_inner < BLOCK_SZ; tx_inner++) {
                if (m >= tx_inner) {
                    int t_index_x = tx_inner + BLOCK_SZ - m;
                    int t_index_y = BLOCK_SZ - tx_inner;
                    temp[t_index_y][t_index_x] = maximum(
                        temp[t_index_y - 1][t_index_x - 1] + ref[t_index_y - 1][t_index_x - 1],
                        temp[t_index_y][t_index_x - 1] - penalty,
                        temp[t_index_y - 1][t_index_x] - penalty);
                }
            }
        }

        for (int ty = 0; ty < BLOCK_SZ; ty++) {
            for (int tx_inner = 0; tx_inner < BLOCK_SZ; tx_inner++) {
                matrix_cuda[index + ty * cols + tx_inner] = temp[ty + 1][tx_inner + 1];
            }
        }
    }
}

